package com.example.banking.service;

import com.example.banking.model.TransactionRequest;
import com.example.banking.model.TransactionResponse;

import javax.jws.WebMethod;
import javax.jws.WebParam;
import javax.jws.WebService;
import javax.jws.soap.SOAPBinding;

@WebService(targetNamespace = "http://service.banking.example.com/",
            name = "BankingService")
@SOAPBinding(style = SOAPBinding.Style.DOCUMENT, use = SOAPBinding.Use.LITERAL)
public interface BankingService {

    @WebMethod
    TransactionResponse processTransaction(
            @WebParam(name = "transactionRequest") TransactionRequest request);
}

